let summaryText = "Sales Summary Report:\n";

for (const item of $input.all()) {
  summaryText += `- ${item.json.Clean_Product} | Status: ${item.json.Clean_Status} | Source: ${item.json.Clean_Source} | Rev: $${item.json.sum_Clean_Price} | Qty: ${item.json.sum_Clean_Qty}\n`;
}

return {
  report_data: summaryText
};

