={{ (function() {
  // 1. الوصول للنص داخل المصفوفة الناتجة من Aggregate1
  const rawOutput = $json.final_report_text[0].output;

  // 2. تنظيف النص وتحويله لـ Object
  const cleanJson = rawOutput.replace(/```json|```/g, '').trim();
  const data = JSON.parse(cleanJson);

  // 3. بناء قالب الإيميل
  return `
  <div dir="rtl" style="font-family: sans-serif; line-height: 1.6; color: #333; padding: 20px; background: #f4f7f6;">
    <div style="max-width: 600px; margin: auto; background: white; padding: 20px; border-radius: 10px; border-top: 8px solid #1e40af;">
      <h2 style="color: #1e40af; text-align: center;">📊 التقرير الاستراتيجي الشامل</h2>

      <p><strong>📝 الملخص التنفيذي:</strong><br>${data.summary}</p>

      <h4 style="color: #1e40af; border-bottom: 1px solid #eee;">🏆 تحليل المنتجات:</h4>
      <p>${data.top_products.overview}</p>

      <h4 style="color: #dc2626; border-bottom: 1px solid #eee;">⚠️ المخاطر المرصودة:</h4>
      <ul>
        ${data.risks.map(r => `<li><strong>${r.risk}:</strong> ${r.details}</li>`).join('')}
      </ul>

      <div style="background: #1e40af; color: white; padding: 15px; border-radius: 8px;">
        <h4 style="margin-top: 0;">💡 التوصيات المقترحة:</h4>
        ${data.recommendations.map(rec => `• <strong>${rec.recommendation}:</strong> ${rec.action}`).join('<br><br>')}
      </div>

      <p style="text-align: center; font-size: 11px; color: #999; margin-top: 20px;">تم التوليد آلياً بواسطة Smart BI System</p>
    </div>
  </div>
  `;
})() }}

